## Task 8: `delete <domain>` command

**File:** `src/TransIp.Dns.Cli/Commands/DnsDeleteCommand.cs`

**Step 1: Implement**

Same option pattern as `add` (--name --type --content; --expire optional, only needed if multiple records match without it):

```csharp
using System.CommandLine;
using TransIp.Dns.Cli.Infrastructure;

namespace TransIp.Dns.Cli.Commands;

public static class DnsDeleteCommand
{
    public static Command Build(/* same five options */)
    {
        var domainArg = new Argument<string>("domain");
        var nameOpt = new Option<string>("--name") { Required = true };
        var typeOpt = new Option<string>("--type") { Required = true };
        var contentOpt = new Option<string>("--content") { Required = true };
        var expireOpt = new Option<int?>("--expire")
        {
            Description = "Match exact TTL (only needed for disambiguation)."
        };

        var cmd = new Command("delete", "Delete a DNS record.");
        cmd.Arguments.Add(domainArg);
        cmd.Options.Add(nameOpt);
        cmd.Options.Add(typeOpt);
        cmd.Options.Add(contentOpt);
        cmd.Options.Add(expireOpt);

        cmd.SetAction(async (parse, ct) =>
        {
            try
            {
                var auth = AuthOptions.Resolve(/* readOnly: false */);
                var client = ClientFactory.Create(auth);
                var domain = parse.GetValue(domainArg)!;

                var all = await client.Domains.GetDnsEntriesAsync(domain, ct);
                var matches = all.Where(e =>
                    e.Name == parse.GetValue(nameOpt) &&
                    string.Equals(e.Type, parse.GetValue(typeOpt),
                        StringComparison.OrdinalIgnoreCase) &&
                    e.Content == parse.GetValue(contentOpt) &&
                    (parse.GetValue(expireOpt) is not int exp || e.Expire == exp))
                    .ToList();

                if (matches.Count == 0)
                    throw new InvalidOperationException("No matching record.");
                if (matches.Count > 1)
                    throw new InvalidOperationException(
                        $"Ambiguous: {matches.Count} records match. " +
                        "Add --expire to disambiguate.");

                await client.Domains.RemoveDnsEntryAsync(domain, matches[0], ct);
                var m = matches[0];
                Console.WriteLine(
                    $"Deleted {m.Type} {m.Name} -> {m.Content} TTL {m.Expire}");
                return 0;
            }
            catch (Exception ex)
            {
                return ErrorHandler.Handle(ex, parse.GetValue(verbose));
            }
        });
        return cmd;
    }
}
```

