## Task 9: `update <domain>` command

TransIP has no record IDs, so update = find exact match + send PATCH with replacement payload. The simplest implementation that always works is: delete the original record, then add the new one. The TransIP API also exposes a direct update endpoint that updates an entry that matches by (name, type) — verify in Task 2 which path is available.

**File:** `src/TransIp.Dns.Cli/Commands/DnsUpdateCommand.cs`

**Step 1: Implement (delete-then-add fallback shown; use direct update if available)**

```csharp
using System.CommandLine;
using TransIp.Dns.Cli.Infrastructure;

namespace TransIp.Dns.Cli.Commands;

public static class DnsUpdateCommand
{
    public static Command Build(/* same five options */)
    {
        var domainArg = new Argument<string>("domain");
        var nameOpt = new Option<string>("--name") { Required = true };
        var typeOpt = new Option<string>("--type") { Required = true };
        var contentOpt = new Option<string>("--content")
        {
            Required = true,
            Description = "Current content of the record to update."
        };
        var newContentOpt = new Option<string?>("--new-content");
        var newExpireOpt = new Option<int?>("--new-expire");

        var cmd = new Command("update",
            "Update a DNS record (matches on name+type+content).");
        cmd.Arguments.Add(domainArg);
        cmd.Options.Add(nameOpt);
        cmd.Options.Add(typeOpt);
        cmd.Options.Add(contentOpt);
        cmd.Options.Add(newContentOpt);
        cmd.Options.Add(newExpireOpt);

        cmd.SetAction(async (parse, ct) =>
        {
            try
            {
                if (parse.GetValue(newContentOpt) is null &&
                    parse.GetValue(newExpireOpt) is null)
                    throw new InvalidOperationException(
                        "Specify --new-content and/or --new-expire.");

                var auth = AuthOptions.Resolve(/* readOnly: false */);
                var client = ClientFactory.Create(auth);
                var domain = parse.GetValue(domainArg)!;

                var all = await client.Domains.GetDnsEntriesAsync(domain, ct);
                var match = all.SingleOrDefault(e =>
                    e.Name == parse.GetValue(nameOpt) &&
                    string.Equals(e.Type, parse.GetValue(typeOpt),
                        StringComparison.OrdinalIgnoreCase) &&
                    e.Content == parse.GetValue(contentOpt))
                    ?? throw new InvalidOperationException(
                        "No (or multiple) matching record(s).");

                var updated = new Apigen.TransIp.Client.Models.DnsEntry
                {
                    Name = match.Name,
                    Type = match.Type,
                    Content = parse.GetValue(newContentOpt) ?? match.Content,
                    Expire = parse.GetValue(newExpireOpt) ?? match.Expire
                };

                // Preferred: direct update if available
                await client.Domains.UpdateDnsEntryAsync(domain, updated, ct);

                Console.WriteLine(
                    $"Updated {updated.Type} {updated.Name} -> " +
                    $"{updated.Content} TTL {updated.Expire}");
                return 0;
            }
            catch (Exception ex)
            {
                return ErrorHandler.Handle(ex, parse.GetValue(verbose));
            }
        });
        return cmd;
    }
}
```

If `UpdateDnsEntryAsync` does not exist, fall back to `RemoveDnsEntryAsync(match)` followed by `AddDnsEntryAsync(updated)`. Document the choice in code comment.

